const items = $input.all();

const seen = new Set();
const unique = [];

for (const item of items) {
  const key = item.json.POHNUM_0;
  if (!seen.has(key)) {
    seen.add(key);
    unique.push(item);
  }
}

return unique;

const items = $input.all();

function normalize(str) {
  return (str || '')
    .toUpperCase()
    .replace(/[''`]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function scoreMatch(ocr, erp) {
  const ocrNorm = normalize(ocr);
  const erpNorm = normalize(erp);
  if (ocrNorm === erpNorm) return 100;
  const ocrWords = new Set(ocrNorm.split(' '));
  const erpWords = new Set(erpNorm.split(' '));
  let common = 0;
  for (const w of ocrWords) {
    if (erpWords.has(w)) common++;
  }
  return (common / Math.max(ocrWords.size, erpWords.size)) * 100;
}

function isConforme(valOcr, valErp) {
  if (valOcr === null || valOcr === undefined || isNaN(valOcr)) return null;
  if (valErp === null || valErp === undefined || isNaN(valErp) || valErp === 0) return null;
  return (Math.abs(valOcr - valErp) / valErp * 100) <= 10;
}

function conformeScore(row, quantiteOcr, montantOcr) {
  const qteConforme     = isConforme(quantiteOcr, parseFloat(row.Quantite));
  const montantConforme = isConforme(montantOcr,  parseFloat(row.montant_ht));
  return (qteConforme === true ? 1 : 0) + (montantConforme === true ? 1 : 0);
}

// ✅ Score global unique qui combine désignation + conformité
// - Désignation OK (≥ seuil) → 10000 + scoreDesig  (toujours prioritaire)
// - Désignation faible       → confScore * 1000 + scoreDesig
//   → une ligne conforme (confScore=1 → 1000+) bat toujours une ligne non-conforme (max 999)
function scoreGlobal(scoreDesig, confScore, seuil) {
  if (scoreDesig >= seuil) return 10000 + scoreDesig;
  return confScore * 1000 + scoreDesig;
}

function buildResult(row, scoreDesig, quantiteOcr, montantOcr) {
  const SCORE_SEUIL = 40;
  let matchConfirme, alerte;

  if (scoreDesig >= SCORE_SEUIL) {
    matchConfirme = true;
    alerte = '';
  } else {
    const qteConforme     = isConforme(quantiteOcr, parseFloat(row.Quantite));
    const montantConforme = isConforme(montantOcr,  parseFloat(row.montant_ht));

    if (qteConforme === true || montantConforme === true) {
      matchConfirme = true;
      alerte = 'Désignation faible — match confirmé par quantité/montant';
    } else if (qteConforme === null && montantConforme === null) {
      matchConfirme = false;
      alerte = 'Désignation faible et données quantité/montant absentes';
    } else {
      matchConfirme = false;
      alerte = 'Désignation faible et aucune cohérence quantité/montant';
    }
  }

  return {
    ...row,
    _score_designation: Math.round(scoreDesig),
    _match_confirme:    matchConfirme,
    _alerte:            alerte
  };
}

const SCORE_SEUIL = 40;

// ── Grouper par designation_ocr + quantite_ocr + montant_ht_ocr ─────
const ocrGroups = {};
for (const item of items) {
  const { designation_ocr, quantite_ocr, montant_ht_ocr } = item.json;
  const compositeKey = `${designation_ocr}||${quantite_ocr ?? ''}||${montant_ht_ocr ?? ''}`;
  if (!ocrGroups[compositeKey]) {
    ocrGroups[compositeKey] = {
      designationOcr: designation_ocr,
      quantiteOcr:    parseFloat(quantite_ocr)   || null,
      montantOcr:     parseFloat(montant_ht_ocr) || null,
      rows: []
    };
  }
  ocrGroups[compositeKey].rows.push(item.json);
}

// ── Pour chaque groupe, choisir la meilleure ligne ERP ───────
const results = [];

for (const group of Object.values(ocrGroups)) {
  const { designationOcr, quantiteOcr, montantOcr, rows } = group;

  let bestRow         = null;
  let bestScoreGlobal = -1;
  let bestMontantDiff = Infinity;

  for (const row of rows) {
    const scoreDesig  = scoreMatch(designationOcr, row.ITMDES1_0);
    const confScore   = conformeScore(row, quantiteOcr, montantOcr);
    const sg          = scoreGlobal(scoreDesig, confScore, SCORE_SEUIL);
    const montantDiff = Math.abs((parseFloat(row.montant_ht) || 0) - (montantOcr || 0));

    const isBetter =
      sg > bestScoreGlobal ||
      (sg === bestScoreGlobal && montantDiff < bestMontantDiff);

    if (isBetter) {
      bestScoreGlobal = sg;
      bestMontantDiff = montantDiff;
      bestRow         = row;
    }
  }

  if (bestRow) {
    const scoreDesigFinal = scoreMatch(designationOcr, bestRow.ITMDES1_0);
    results.push({ json: buildResult(bestRow, scoreDesigFinal, quantiteOcr, montantOcr) });
  }
}

return results;

